// ─── Doctor Report Parsing ───

describe('parseReport — Doctor', () => {
  it('extracts the title', () => {
    const result = parseReport(DOCTOR_REPORT, 'doctor')
    expect(result.title).toBe('Project Diagnostic Report')
  })

  it('strips redundant metadata (Generated by line)', () => {
    const result = parseReport(DOCTOR_REPORT, 'doctor')
    expect(result.metadata).toBe('')
  })

  it('parses 6 sections with correct headings', () => {
    const result = parseReport(DOCTOR_REPORT, 'doctor')
    expect(result.sections).toHaveLength(6)
    expect(result.sections[0].heading).toContain('Patient summary')
    expect(result.sections[1].heading).toContain('Diagnosis')
    expect(result.sections[2].heading).toContain('Symptoms vs. root cause')
    expect(result.sections[3].heading).toContain('Risk level')
    expect(result.sections[4].heading).toContain('Recommended actions')
    expect(result.sections[5].heading).toContain("What the AI can't see")
  })

  it('extracts CTA footer with Full Stack Human and calendly link', () => {
    const result = parseReport(DOCTOR_REPORT, 'doctor')
    expect(result.ctaFooter).toContain('Full Stack Human')
    expect(result.ctaFooter.toLowerCase()).toContain('calendly')
  })

  it('sets persona to doctor', () => {
    const result = parseReport(DOCTOR_REPORT, 'doctor')
    expect(result.persona).toBe('doctor')
  })

  it('detects root-cause-flow visual in Symptoms vs root cause section (index 2)', () => {
    const result = parseReport(DOCTOR_REPORT, 'doctor')
    const signatureSection = result.sections[2]
    expect(signatureSection.visual).not.toBeNull()
    expect(signatureSection.visual!.type).toBe('root-cause-flow')

    const data = signatureSection.visual!.data as {
      rows: Array<{ symptom: string; rootCause: string }>
    }
    expect(data.rows).toHaveLength(3)
    expect(data.rows[0].symptom).toContain('missing deadlines')
    expect(data.rows[0].rootCause).toContain('Scope creep')
  })

  it('detects risk-gauge visual in Risk level section (index 3)', () => {
    const result = parseReport(DOCTOR_REPORT, 'doctor')
    const riskSection = result.sections[3]
    expect(riskSection.visual).not.toBeNull()
    expect(riskSection.visual!.type).toBe('risk-gauge')

    const data = riskSection.visual!.data as { level: string }
    expect(data.level).toBe('high')
  })

  it('detects priority-roadmap visual in Recommended actions section (index 4)', () => {
    const result = parseReport(DOCTOR_REPORT, 'doctor')
    const actionsSection = result.sections[4]
    expect(actionsSection.visual).not.toBeNull()
    expect(actionsSection.visual!.type).toBe('priority-roadmap')

    const data = actionsSection.visual!.data as {
      items: Array<{ index: number; label: string; fullText: string }>
    }
    expect(data.items).toHaveLength(3)
    expect(data.items[0].label).toContain('Define the MVP scope')
    expect(data.items[1].label).toContain('Talk to 10 users this week')
    expect(data.items[2].label).toContain('Kill the roadmap')
  })

  it('strips markdown table from root-cause-flow section content', () => {
    const result = parseReport(DOCTOR_REPORT, 'doctor')
    const signatureSection = result.sections[2]
    // Table source markdown should be stripped when visual is detected
    expect(signatureSection.content).not.toContain('| What it looks like')
    expect(signatureSection.content).not.toContain('| --- |')
    expect(signatureSection.content).not.toContain('missing deadlines')
  })

  it('strips risk level keyword from risk-gauge section content', () => {
    const result = parseReport(DOCTOR_REPORT, 'doctor')
    const riskSection = result.sections[3]
    // The standalone "High" line should be stripped
    expect(riskSection.content).not.toMatch(/^High$/m)
    // But the elaboration text should remain
    expect(riskSection.content).toContain('nothing changes')
  })

  it('strips numbered list from priority-roadmap section content', () => {
    const result = parseReport(DOCTOR_REPORT, 'doctor')
    const actionsSection = result.sections[4]
    // Numbered items should be stripped when visual is detected
    expect(actionsSection.content).not.toContain('1.')
    expect(actionsSection.content).not.toContain('2.')
    expect(actionsSection.content).not.toContain('3.')
  })

  it('does not attach visuals to non-visual sections', () => {
    const result = parseReport(DOCTOR_REPORT, 'doctor')
    // Patient summary (index 0) and Diagnosis (index 1) have no visuals
    expect(result.sections[0].visual).toBeNull()
    expect(result.sections[1].visual).toBeNull()
    // What the AI can't see (index 5) has no visual
    expect(result.sections[5].visual).toBeNull()
  })

  it('section indices are sequential starting from 0', () => {
    const result = parseReport(DOCTOR_REPORT, 'doctor')
    result.sections.forEach((section, i) => {
      expect(section.index).toBe(i)
    })
  })
})

// ─── Critic Report Parsing ───

describe('parseReport — Critic', () => {
  it('parses 6 sections', () => {
    const result = parseReport(CRITIC_REPORT, 'critic')
    expect(result.sections).toHaveLength(6)
  })

  it('extracts title', () => {
    const result = parseReport(CRITIC_REPORT, 'critic')
    expect(result.title).toBe('Review Brief')
  })

  it('strips the assessment-radar fenced block from section content', () => {
    const result = parseReport(CRITIC_REPORT, 'critic')
    const section0 = result.sections[0]
    // The fenced block JSON should not appear in the content
    expect(section0.content).not.toContain('assessment-radar')
    expect(section0.content).not.toContain('"dimensions"')
  })

  it('attaches assessment-radar visual to section 0 (What I reviewed)', () => {
    const result = parseReport(CRITIC_REPORT, 'critic')
    const section0 = result.sections[0]
    expect(section0.visual).not.toBeNull()
    expect(section0.visual!.type).toBe('assessment-radar')

    const data = section0.visual!.data as {
      dimensions: Array<{ name: string; score: number }>
    }
    expect(data.dimensions).toHaveLength(5)
    expect(data.dimensions[0].name).toBe('Value Proposition')
    expect(data.dimensions[0].score).toBe(7)
    expect(data.dimensions[4].name).toBe('Team Story')
    expect(data.dimensions[4].score).toBe(6)
  })

  it('detects priority-roadmap in section 4 (If I had to prioritize)', () => {
    const result = parseReport(CRITIC_REPORT, 'critic')
    const section4 = result.sections[4]
    expect(section4.visual).not.toBeNull()
    expect(section4.visual!.type).toBe('priority-roadmap')

    const data = section4.visual!.data as {
      items: Array<{ label: string }>
    }
    expect(data.items).toHaveLength(3)
  })

  it('extracts CTA footer', () => {
    const result = parseReport(CRITIC_REPORT, 'critic')
    expect(result.ctaFooter).toContain('Full Stack Human')
    expect(result.ctaFooter.toLowerCase()).toContain('calendly')
  })
})

// ─── Guide Report Parsing ───

describe('parseReport — Guide', () => {
  it('parses 6 sections', () => {
    const result = parseReport(GUIDE_REPORT_WITH_FRAMEWORK_MATRIX, 'guide')
    expect(result.sections).toHaveLength(6)
  })

  it('extracts title', () => {
    const result = parseReport(GUIDE_REPORT_WITH_FRAMEWORK_MATRIX, 'guide')
    expect(result.title).toBe('Framework Brief')
  })

  it('attaches framework-matrix visual to section 1 (How to think about this)', () => {
    const result = parseReport(GUIDE_REPORT_WITH_FRAMEWORK_MATRIX, 'guide')
    const section1 = result.sections[1]
    expect(section1.visual).not.toBeNull()
    expect(section1.visual!.type).toBe('framework-matrix')

    const data = section1.visual!.data as {
      title: string
      xAxisLabel: string
      yAxisLabel: string
      quadrants: Record<string, { label: string; description: string }>
      userPosition?: { x: number; y: number }
    }
    expect(data.title).toBe('Team Building Approach')
    expect(data.xAxisLabel).toBe('Structure')
    expect(data.yAxisLabel).toBe('Autonomy')
    expect(data.quadrants.topRight.label).toBe('Empowered teams')
    expect(data.userPosition).toEqual({ x: 0.3, y: 0.7 })
  })

  it('strips the framework-matrix fenced block from content', () => {
    const result = parseReport(GUIDE_REPORT_WITH_FRAMEWORK_MATRIX, 'guide')
    const section1 = result.sections[1]
    expect(section1.content).not.toContain('framework-matrix')
    expect(section1.content).not.toContain('"xAxisLabel"')
    // But the surrounding text should remain
    expect(section1.content).toContain('framework above')
  })

  it('extracts CTA footer', () => {
    const result = parseReport(GUIDE_REPORT_WITH_FRAMEWORK_MATRIX, 'guide')
    expect(result.ctaFooter).toContain('Full Stack Human')
  })
})

// ─── Template Config Consistency ───

describe('PERSONA_TEMPLATE_CONFIGS', () => {
  it('has configs for all three personas', () => {
    expect(PERSONA_TEMPLATE_CONFIGS).toHaveProperty('doctor')
    expect(PERSONA_TEMPLATE_CONFIGS).toHaveProperty('critic')
    expect(PERSONA_TEMPLATE_CONFIGS).toHaveProperty('guide')
  })

  it('doctor signature section is index 2', () => {
    expect(PERSONA_TEMPLATE_CONFIGS.doctor.signatureSectionIndex).toBe(2)
  })

  it('critic signature section is index 3', () => {
    expect(PERSONA_TEMPLATE_CONFIGS.critic.signatureSectionIndex).toBe(3)
  })

  it('guide signature section is index 2', () => {
    expect(PERSONA_TEMPLATE_CONFIGS.guide.signatureSectionIndex).toBe(2)
  })
})

